use strict;
use warnings;

use 5.012000;
use ExtUtils::MakeMaker;

# Probe the host's SysV IPC implementation at configure time.
#
# IPC::Manager ships a SharedMem protocol that uses SysV semaphores and
# shared memory.  On a small number of CPAN tester hosts those primitives
# behave incorrectly (we have observed sporadic EINVAL from semop on
# freshly-created semaphores under perl 5.32 / 5.36 on certain Debian
# kernels), which makes the SharedMem integration tests fail in
# confusing ways.
#
# Rather than blocking the whole distribution from installing on such
# hosts, when the probe fails we surgically disable just the SharedMem
# module: we flip its `$BROKEN_SYSV_IPC` package variable from 0 to 1
# in lib/IPC/Manager/Client/SharedMem.pm.  The module still loads, but
# its _viable() method throws an exception explaining how to recover.
# All other protocols install normally.  The matching test files use
# viable() to detect the disabled state and skip_all themselves, so
# the build still PASSes on these hosts.
#
# This probe uses only core perl SysV builtins (semget / semop / shmget
# / shmread / shmwrite / shmctl / semctl); it never loads or calls into
# IPC::Manager.  A regression in our own SharedMem code therefore
# cannot reach this probe -- only environmental SysV breakage triggers
# the disable.

PROBE_SYSV: {
    last PROBE_SYSV
        unless eval { require IPC::SysV; IPC::SysV->VERSION('2.09'); 1 };

    my $IPC_PRIVATE = IPC::SysV::IPC_PRIVATE();
    my $IPC_CREAT   = IPC::SysV::IPC_CREAT();
    my $IPC_RMID    = IPC::SysV::IPC_RMID();
    my $S_IRUSR     = IPC::SysV::S_IRUSR();
    my $S_IWUSR     = IPC::SysV::S_IWUSR();
    my $mask        = $S_IRUSR | $S_IWUSR | $IPC_CREAT;

    my $LOCK   = pack("s!3", 0, -1, 0);
    my $UNLOCK = pack("s!3", 0,  1, 0);

    my $reason;

    my $dance = sub {
        my $sem_id = semget($IPC_PRIVATE, 1, $mask);
        return "semget failed: $!" unless defined $sem_id;

        unless (semop($sem_id, $UNLOCK)) {
            my $err = "init semop failed: $!";
            semctl($sem_id, 0, $IPC_RMID, 0);
            return $err;
        }

        for (1 .. 10) {
            unless (semop($sem_id, $LOCK)) {
                my $err = "lock semop failed: $!";
                semctl($sem_id, 0, $IPC_RMID, 0);
                return $err;
            }
            unless (semop($sem_id, $UNLOCK)) {
                my $err = "unlock semop failed: $!";
                semctl($sem_id, 0, $IPC_RMID, 0);
                return $err;
            }
        }

        my $shm_id = shmget($IPC_PRIVATE, 4096, $mask);
        unless (defined $shm_id) {
            my $err = "shmget failed: $!";
            semctl($sem_id, 0, $IPC_RMID, 0);
            return $err;
        }

        my $payload = "ipc-manager-probe-payload";
        unless (shmwrite($shm_id, $payload, 0, length $payload)) {
            my $err = "shmwrite failed: $!";
            shmctl($shm_id, $IPC_RMID, 0);
            semctl($sem_id, 0, $IPC_RMID, 0);
            return $err;
        }

        my $buf = '';
        unless (shmread($shm_id, $buf, 0, length $payload)) {
            my $err = "shmread failed: $!";
            shmctl($shm_id, $IPC_RMID, 0);
            semctl($sem_id, 0, $IPC_RMID, 0);
            return $err;
        }

        if ($buf ne $payload) {
            shmctl($shm_id, $IPC_RMID, 0);
            semctl($sem_id, 0, $IPC_RMID, 0);
            return "shmread returned wrong data";
        }

        shmctl($shm_id, $IPC_RMID, 0);
        semctl($sem_id, 0, $IPC_RMID, 0);
        return undef;
    };

    # Single-process dance.
    $reason = $dance->();

    # Cross-fork dance: parent creates the semaphore, the child
    # repeatedly locks/unlocks it, parent reaps and then exercises it
    # again.  Mirrors how IPC::Manager actually uses SysV across
    # forked service processes.
    if (!$reason) {
        my $sem_id = semget($IPC_PRIVATE, 1, $mask);
        if (!defined $sem_id) {
            $reason = "fork-probe semget failed: $!";
        }
        elsif (!semop($sem_id, $UNLOCK)) {
            $reason = "fork-probe init semop failed: $!";
            semctl($sem_id, 0, $IPC_RMID, 0);
        }
        else {
            my $pid = fork;
            if (!defined $pid) {
                $reason = "fork-probe fork failed: $!";
                semctl($sem_id, 0, $IPC_RMID, 0);
            }
            elsif (!$pid) {
                # child
                require POSIX;
                for (1 .. 5) {
                    semop($sem_id, $LOCK)   or POSIX::_exit(2);
                    semop($sem_id, $UNLOCK) or POSIX::_exit(3);
                }
                POSIX::_exit(0);
            }
            else {
                waitpid($pid, 0);
                my $status = $?;
                if ($status) {
                    $reason = "fork-probe child exited non-zero (status=$status)";
                }
                else {
                    for (1 .. 5) {
                        unless (semop($sem_id, $LOCK)) {
                            $reason = "fork-probe parent post-child lock failed: $!";
                            last;
                        }
                        unless (semop($sem_id, $UNLOCK)) {
                            $reason = "fork-probe parent post-child unlock failed: $!";
                            last;
                        }
                    }
                }
                semctl($sem_id, 0, $IPC_RMID, 0);
            }
        }
    }

    last PROBE_SYSV unless $reason;

    # Refuse to munge our own source tree.  The released tarball will
    # not contain inc/configure-probe.pl (it is excluded from the
    # GatherDir build), so a developer running `perl Makefile.PL`
    # against the git checkout never gets their lib/ poisoned.
    last PROBE_SYSV if -e 'inc/configure-probe.pl';

    my $target = 'lib/IPC/Manager/Client/SharedMem.pm';
    last PROBE_SYSV unless -f $target;

    open my $in, '<', $target
        or do { warn "Could not open $target to disable SharedMem: $!"; last PROBE_SYSV };
    my $src = do { local $/; <$in> };
    close $in;

    # Flip `our $BROKEN_SYSV_IPC = 0;` to 1 so _viable() throws.
    unless ($src =~ s/^(our \$BROKEN_SYSV_IPC = )0;/${1}1;/m) {
        # Already flipped, or the variable is missing.
        if ($src =~ /\$BROKEN_SYSV_IPC\s*=\s*1\s*;/) {
            last PROBE_SYSV;     # idempotent: nothing to do
        }
        warn "Could not locate \$BROKEN_SYSV_IPC in $target; SharedMem will not be disabled.\n";
        last PROBE_SYSV;
    }

    open my $out, '>', $target
        or do { warn "Could not write $target to disable SharedMem: $!"; last PROBE_SYSV };
    print $out $src;
    close $out;

    print STDOUT <<"EOM";

*** IPC::Manager::Client::SharedMem disabled at install time ***

Your system's SysV IPC implementation appears to be broken:
  $reason

The SharedMem protocol requires working SysV semaphores and shared
memory.  IPC::Manager will install normally and all other protocols
remain available, but IPC::Manager::Client::SharedMem->viable will
throw an exception explaining how to recover.

EOM
}

